('rank_math_pro_google_updates', '[{\"link\":\"https:\\/\\/rankmath.com\\/google-update\\/may-2026-core-update\\/\",\"title\":\"May 2026 Core Update\",\"content\":\"Google released the May 2026 Core Update on May 21, 2026, and said the rollout is expected to take up to two weeks.\",\"date\":\"1779321600\",\"status\":\"confirmed\"},{\"link\":\"https:\\/\\/rankmath.com\\/google-update\\/march-2026-core-update\\/\",\"title\":\"March 2026 Core Update\",\"content\":\"Google released the March 2026 Core Update between March 27 and April 8, 2026. The rollout was completed within two weeks, and according to Google, improved how relevant content is served to users.\",\"date\":\"1774569600\",\"status\":\"confirmed\"},{\"link\":\"https:\\/\\/rankmath.com\\/google-update\\/march-2026-spam-update\\/\",\"title\":\"March 2026 Spam Update\",\"content\":\"Google released an update to its spam system between March 24 and 25, 2026. The update lasted below 20 hours, making it Google\\u0027s fastest update ever.\",\"date\":\"1774310400\",\"status\":\"confirmed\"},{\"link\":\"https:\\/\\/rankmath.com\\/google-update\\/february-2026-discover-core-update\\/\",\"title\":\"February 2026 Discover Core Update\",\"content\":\"Google rolled out the February 2026 Discover Core Update from February 5 to February 27, 2026. This is Google’s first update to Discover and only targets English users in the United States.\",\"date\":\"1770249600\",\"status\":\"confirmed\"},{\"link\":\"https:\\/\\/rankmath.com\\/google-update\\/december-2025-core-update\\/\",\"title\":\"December 2025 Core Update\",\"content\":\"Google released the December 2025 Core Update between December 11 and December 29, 2025. The update caused significant volatility across many sites in various verticals.\",\"date\":\"1765411200\",\"status\":\"confirmed\"}]', 'off'),
