('rank_math_content_ai_prompts', 'a:130:{i:0;a:4:{s:10:\"PromptIcon\";s:4:\"🎨\";s:10:\"PromptName\";s:21:\"Create Ad for Product\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:103:\"Create an ad for [company/product], emphasizing [key feature/benefit], to convince readers to [action].\";}i:1;a:4:{s:10:\"PromptIcon\";s:4:\"📝\";s:10:\"PromptName\";s:23:\"Blog Post - Fix Grammar\";s:14:\"PromptCategory\";s:4:\"blog\";s:6:\"Prompt\";s:133:\"Edit the blog text on [topic or title], ensuring correct grammar, punctuation, and syntax. Improve readability and clarity as needed.\";}i:2;a:4:{s:10:\"PromptIcon\";s:4:\"📰\";s:10:\"PromptName\";s:16:\"Blog Post - News\";s:14:\"PromptCategory\";s:4:\"blog\";s:6:\"Prompt\";s:304:\"Generate a News Article: Provide Details\n \n\n 1. Headline: [Enter headline]\n 2. Date: [Enter date]\n 3. Location: [Enter location]\n 4. Main Event: [Describe event]\n 5. Key Players: [List people involved]\n 6. Impact: [Explain impact]\n 7. Quotes: [Provide quotes]\n 8. Additional Info: [Include other details]\";}i:3;a:4:{s:10:\"PromptIcon\";s:4:\"📚\";s:10:\"PromptName\";s:32:\"Blog Post – Beginner’s guide\";s:14:\"PromptCategory\";s:4:\"blog\";s:6:\"Prompt\";s:146:\"Write a beginner\'s guide blog post on [topic or skill] for new users. The 1000-1500 word post should include practical tips, advice, and examples.\";}i:4;a:4:{s:10:\"PromptIcon\";s:4:\"📖\";s:10:\"PromptName\";s:28:\"Blog Post – Personal story\";s:14:\"PromptCategory\";s:4:\"blog\";s:6:\"Prompt\";s:165:\"Write a 1000-1500 word personal story-style blog post about [topic or event], with relatable anecdotes, reflections, and insights on experiences and lessons learned.\";}i:5;a:4:{s:10:\"PromptIcon\";s:4:\"📝\";s:10:\"PromptName\";s:10:\"Blog Title\";s:14:\"PromptCategory\";s:4:\"blog\";s:6:\"Prompt\";s:78:\"Craft a captivating blog post title on [topic] with these keywords [keywords].\";}i:6;a:4:{s:10:\"PromptIcon\";s:4:\"🚀\";s:10:\"PromptName\";s:24:\"Boost Customer Retention\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:73:\"Devise customer success strategies for [company name] to boost retention.\";}i:7;a:4:{s:10:\"PromptIcon\";s:4:\"📚\";s:10:\"PromptName\";s:22:\"Brand Content Strategy\";s:14:\"PromptCategory\";s:4:\"blog\";s:6:\"Prompt\";s:127:\"Create a content strategy for [brand], with blog and social media posts for [time period]. Include topics, ideas, and timeline.\";}i:8;a:4:{s:10:\"PromptIcon\";s:6:\"♻️\";s:10:\"PromptName\";s:26:\"Brand Remarketing Strategy\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:135:\"Develop a remarketing plan for [brand_name] to achieve [desired_outcome]. Provide a strategy overview, objectives, and [number] budget.\";}i:9;a:4:{s:10:\"PromptIcon\";s:6:\"✉️\";s:10:\"PromptName\";s:31:\"Captivating Email Subject Lines\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:158:\"Create [number] engaging subject lines for [email type] about [product name and description] targeting [specific audience]. Limit each line to [number] words.\";}i:10;a:4:{s:10:\"PromptIcon\";s:4:\"🏆\";s:10:\"PromptName\";s:25:\"Captivating Success Story\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:173:\"Write a customer success story for [company name] featuring [customer_name] using [product/service]. Include a clear introduction, body, and conclusion with customer quotes.\";}i:11;a:4:{s:10:\"PromptIcon\";s:4:\"🤝\";s:10:\"PromptName\";s:26:\"Client Concerns Resolution\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:92:\"Identify [5] client concerns about [product/service] and provide written responses for each.\";}i:12;a:4:{s:10:\"PromptIcon\";s:4:\"📑\";s:10:\"PromptName\";s:26:\"Client Gathering Blueprint\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:121:\"Plan a client gathering at [location] with [number] participants, focusing on [topic/product]. Include budget and agenda.\";}i:13;a:4:{s:10:\"PromptIcon\";s:4:\"📊\";s:10:\"PromptName\";s:21:\"Client Input Analysis\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:97:\"Analyze client input on [product/service] for improvement areas. Feedback: [insert feedback here]\";}i:14;a:4:{s:10:\"PromptIcon\";s:11:\"🧑‍💼\";s:10:\"PromptName\";s:26:\"Client Persona Development\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:132:\"Create customer personas for [company name] with a market research on [demographic]; summarize their needs, preferences, and values.\";}i:15;a:4:{s:10:\"PromptIcon\";s:4:\"💼\";s:10:\"PromptName\";s:21:\"Client Sales Proposal\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:156:\"Create a sales proposal for [client name], highlighting [product advantages], summarizing [expenses], including a project timeline, and anticipated results.\";}i:16;a:4:{s:10:\"PromptIcon\";s:4:\"📞\";s:10:\"PromptName\";s:22:\"Cold Call Sales Script\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:101:\"Create a cold call sales script detailing [product] for [prospect] and encouraging a demo scheduling.\";}i:17;a:4:{s:10:\"PromptIcon\";s:4:\"📚\";s:10:\"PromptName\";s:20:\"Company Naming Guide\";s:14:\"PromptCategory\";s:3:\"seo\";s:6:\"Prompt\";s:110:\"Create a naming convention for [company_name] with [number] items: [list_of_items]. Explain each name briefly.\";}i:18;a:4:{s:10:\"PromptIcon\";s:4:\"📰\";s:10:\"PromptName\";s:26:\"Company Newsletters Update\";s:14:\"PromptCategory\";s:15:\"marketing-sales\";s:6:\"Prompt\";s:159:\"Create email newsletters for [company_name] with updates on [product/service] and upcoming [events/promotions]. Include a call to action for reader engagement.\";}i:19;a:4:{s:10:\"PromptIcon\";s:4:\"📊\";s:10:\"PromptName\";s:32:\"Competitive Environment Analysis\";s:14:\"PromptCategory\";s:3:\"seo\";s:6:\"Prompt\";s:128:\"Research the [keyword] competitive landscape, identify the top [number] competitors, and analyze their s